import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [employees, setEmployees] = useState([]);

  // Hàm gọi API từ Backend Java của bạn
  useEffect(() => {
    axios.get("http://localhost:8080/api/employees")
        .then(response => {
          setEmployees(response.data); // Lưu dữ liệu vào biến employees
        })
        .catch(error => console.error("Lỗi rồi Thái ơi:", error));
  }, []);

  return (
      <div style={{ padding: "50px", fontFamily: "Arial" }}>
        <h1>Danh sách Nhân viên - PTIT</h1>
        <table border="1" cellPadding="10" style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
          <tr style={{ backgroundColor: "#f2f2f2" }}>
            <th>ID</th>
            <th>Họ và Tên</th>
            <th>Phòng ban</th>
            <th>Chức vụ</th>
          </tr>
          </thead>
          <tbody>
          {employees.map(emp => (
              <tr key={emp.id}>
                <td>{emp.id}</td>
                <td>{emp.fullName}</td>
                <td>{emp.department}</td>
                <td>{emp.position}</td>
              </tr>
          ))}
          </tbody>
        </table>
      </div>
  );
}

export default App;
